// Classify incoming email: is it a job application response?
const email = $input.item.json;
const subject = (email.subject || '').toLowerCase();
const body = (email.text || email.body || email.snippet || '').toLowerCase();
const from = (email.from || '').toLowerCase();

// Detection patterns
const rejectionKeywords = [
  'unfortunately', 'not moving forward', 'not be moving', 'decided to move',
  'other candidates', 'not a match', 'not fit', 'unsuccessful', 'regret',
  'not selected', 'filled the position', 'no longer considering',
  'decided not to', 'position has been filled', 'will not be proceeding'
];

const interviewKeywords = [
  'interview', 'schedule', 'availability', 'phone screen', 'technical interview',
  'next steps', 'speak with you', 'chat with you', 'calendar', 'zoom', 'meet'
];

const offerKeywords = [
  'offer', 'congratulations', 'pleased to offer', 'job offer', 'we\'d like to offer',
  'compensation', 'start date', 'onboarding'
];

const ghostingKeywords = ['follow up', 'following up', 'checking in', 'any update'];

let emailType = 'unknown';
let stage = 'unknown';

// Detect rejection stage from body
let rejectionStage = 'unknown';
if (body.includes('phone') || body.includes('initial')) rejectionStage = 'phone_screen';
else if (body.includes('technical') || body.includes('coding') || body.includes('assessment')) rejectionStage = 'technical';
else if (body.includes('final') || body.includes('onsite') || body.includes('panel')) rejectionStage = 'final_round';
else rejectionStage = 'application';

if (rejectionKeywords.some(function(kw) { return subject.includes(kw) || body.includes(kw); })) {
  emailType = 'rejection';
  stage = rejectionStage;
} else if (offerKeywords.some(function(kw) { return subject.includes(kw) || body.includes(kw); })) {
  emailType = 'offer';
  stage = 'offer';
} else if (interviewKeywords.some(function(kw) { return subject.includes(kw) || body.includes(kw); })) {
  emailType = 'interview_invite';
  stage = 'interview';
} else if (subject.includes('application') || subject.includes('received') || subject.includes('thank you')) {
  emailType = 'acknowledgement';
  stage = 'applied';
}

// Extract company name from subject/from
const companyFromSubject = subject.replace(/re:|fwd:|fw:|application|position|role|job/gi, '').trim();

return [{
  json: {
    ...email,
    email_type: emailType,
    rejection_stage: stage,
    company_hint: companyFromSubject.substring(0, 50),
    classified_at: new Date().toISOString()
  }
}];

// Context-aware rejection response based on stage reached
const data = $input.item.json;
const stage = data.rejection_stage || 'application';
const company = data.company_hint || 'the company';

let responseTemplate = '';
let folderTarget = 'Rejected';
let obsidianStatus = 'Rejected';

if (stage === 'phone_screen') {
  responseTemplate =
    'Subject: Thank You - ' + company + ' Application\n\n' +
    'Hi [Recruiter Name],\n\n' +
    'Thank you for letting me know about the decision. I appreciate you taking the time to speak with me during the phone screen.\n\n' +
    'I enjoyed learning about ' + company + ' and the role. While I\'m disappointed, I understand the competitive nature of these decisions.\n\n' +
    'I\'d be grateful for any feedback on my candidacy - it would help me improve for future opportunities.\n\n' +
    'I hope to stay in touch and potentially work together in the future.\n\n' +
    'Best regards,\nOdeliya Charitonova';
} else if (stage === 'technical') {
  responseTemplate =
    'Subject: Thank You - ' + company + ' Technical Interview\n\n' +
    'Hi [Interviewer Name],\n\n' +
    'Thank you for informing me of the decision. I really enjoyed the technical discussions and the challenging problems we explored together.\n\n' +
    'If you\'re able to share any feedback on my technical performance, I\'d greatly appreciate it - I\'m always looking to improve.\n\n' +
    'I have a lot of respect for the engineering culture at ' + company + ' and hope our paths cross again.\n\n' +
    'Best regards,\nOdeliya Charitonova';
} else if (stage === 'final_round') {
  responseTemplate =
    'Subject: Thank You - ' + company + ' Interview Process\n\n' +
    'Hi [Hiring Manager Name],\n\n' +
    'Thank you for informing me of your decision after such a thorough process. I was genuinely excited about the opportunity and the team at ' + company + '.\n\n' +
    'Going through the final round gave me great insight into how you approach engineering challenges, and I have enormous respect for what you\'re building.\n\n' +
    'I\'d welcome the opportunity to stay connected - and I\'d be very grateful for any specific feedback you can share.\n\n' +
    'I hope we can find an opportunity to work together in the future.\n\n' +
    'Best regards,\nOdeliya Charitonova';
} else {
  responseTemplate =
    'Subject: Thank You - ' + company + ' Application\n\n' +
    'Hi,\n\n' +
    'Thank you for letting me know. I appreciate your transparency and wish the team all the best.\n\n' +
    'I\'d be happy to be considered for future opportunities that might be a better match.\n\n' +
    'Best regards,\nOdeliya Charitonova';
}

return [{
  json: {
    ...data,
    response_template: responseTemplate,
    folder_target: folderTarget,
    obsidian_status: obsidianStatus,
    status_update: 'Rejected - ' + stage,
    update_timestamp: new Date().toISOString()
  }
}];

// Update Obsidian vault via GitHub API - move file to correct status folder
const githubToken = process.env.GITHUB_TOKEN || '';
const data = $input.item.json;

if (!githubToken) {
  return [{ json: { ...data, obsidian_update: 'skipped - no token' } }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const newStatus = data.obsidian_status || 'Active';
const emailType = data.email_type || 'unknown';

// Log the email type and status for tracking
const logEntry =
  '## Email Received: ' + new Date().toISOString().substring(0, 10) + '\n' +
  '- Type: ' + emailType + '\n' +
  '- Stage: ' + (data.rejection_stage || 'N/A') + '\n' +
  '- Status: ' + newStatus + '\n' +
  '- Subject: ' + (data.subject || '') + '\n\n';

try {
  const headers = {
    'Authorization': 'token ' + githubToken,
    'Accept': 'application/vnd.github.v3+json',
    'Content-Type': 'application/json'
  };

  // Search for existing tracking file in Active folder
  const searchResp = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/refs/heads/main',
    headers: headers
  });

  // Create a status log file in the vault
  const statusLogPath = 'Obsidian_Vault/Email_Log/' + new Date().toISOString().substring(0, 10) + '-' + emailType + '.md';
  const statusContent =
    '# Email Log: ' + (data.subject || 'Unknown Subject') + '\n\n' +
    '- **Date:** ' + new Date().toISOString().substring(0, 10) + '\n' +
    '- **From:** ' + (data.from || 'Unknown') + '\n' +
    '- **Type:** ' + emailType + '\n' +
    '- **Stage:** ' + (data.rejection_stage || 'N/A') + '\n' +
    '- **New Status:** ' + newStatus + '\n\n' +
    '## Response Template\n\n' + (data.response_template || 'N/A') + '\n';

  const currentSha = searchResp.object.sha;
  const commitData = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/commits/' + currentSha,
    headers: headers
  });

  const blobResp = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/blobs',
    headers: headers,
    body: {
      content: Buffer.from(statusContent).toString('base64'),
      encoding: 'base64'
    }
  });

  const treeResp = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/trees',
    headers: headers,
    body: {
      base_tree: commitData.tree.sha,
      tree: [{ path: statusLogPath, mode: '100644', type: 'blob', sha: blobResp.sha }]
    }
  });

  const newCommit = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/commits',
    headers: headers,
    body: {
      message: 'Email received: ' + emailType + ' - ' + (data.subject || '').substring(0, 50),
      tree: treeResp.sha,
      parents: [currentSha],
      author: { name: 'Odeliya Charitonova', email: 'odaliya12@gmail.com', date: new Date().toISOString() }
    }
  });

  await $helpers.httpRequest({
    method: 'PATCH',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/refs/heads/main',
    headers: headers,
    body: { sha: newCommit.sha, force: false }
  });

  return [{ json: { ...data, obsidian_update: 'success', log_path: statusLogPath } }];
} catch (e) {
  return [{ json: { ...data, obsidian_update: 'error', obsidian_error: e.message } }];
}

const data = $input.item.json;
return [{
  json: {
    ...data,
    obsidian_status: 'Active',
    folder_target: 'Active',
    status_update: 'Interview Invited',
    update_timestamp: new Date().toISOString()
  }
}];

const data = $input.item.json;
return [{
  json: {
    ...data,
    obsidian_status: 'Offers',
    folder_target: 'Offers',
    status_update: 'Offer Received',
    update_timestamp: new Date().toISOString()
  }
}];
